import{c as r}from"./DffLFeIZ.js";const c={async getHealth(){return(await r.get("/mrd/health")).data},async searchPatients(t){return(await r.get("/mrd/patients/search",{params:t})).data},async getRecords(t){return(await r.get("/mrd/records",{params:t})).data},async getRecord(t){return(await r.get(`/mrd/records/${t}`)).data},async getPrescriptions(t){return(await r.get("/mrd/prescriptions",{params:t})).data},async getReports(t){return(await r.get("/mrd/reports",{params:t})).data},async getAdmissions(t){return(await r.get("/mrd/admissions",{params:t})).data},async createExport(t){return(await r.post("/mrd/exports",t)).data},async listExports(){return(await r.get("/mrd/exports")).data},async getExport(t){return(await r.get(`/mrd/exports/${t}`)).data},async getCensus(t){return(await r.get("/mrd/census",{params:t})).data},async getCensusPatients(t){const{category:e,...s}=t;return(await r.get(`/mrd/census/${e}/patients`,{params:s})).data},async getDepartmentBreakdown(t){return(await r.get("/mrd/census/department-breakdown",{params:t})).data},async getLabs(){return(await r.get("/mrd/labs")).data}};export{c as m};
